#include <stdio.h>

int main(int argc, const char * argv[]) {
    int n, i, j;
    scanf("%d", &n);
    int years[n];
    for (i = 0; i < n; i++) {
        scanf("%d", &years[i]);
    }
    for (i = 0; i < n; i++) {
        for (j = 0 ; j < n; j++) {
            if (years[j] > years[i]) {

                years[i] = years[i] + years[j];
                years[j] = years[i] - years[j];
                years[i] = years[i] - years[j];
            }
        }
    }
//    for (i = 0; i < n; i++) {
//        printf("%d", years[i]);
//    }
    if (n == 1) {
        printf("%d", years[0]);
    } else if (n == 3) {
        printf("%d", years[1]);
    } else if (n == 5) {
        printf("%d", years[2]);
    }
    return 0;
}

